<template>
	<view>
		<uni-card is-full :is-shadow="false">
			<text class="uni-h6">иҝҷжҳҜжҠҪеұүејҸеҜјиҲӘз»„д»¶дҪҝз”ЁзӨәдҫӢпјҢеҸҜд»ҘжҢҮе®ҡиҸңеҚ•е·Ұдҫ§жҲ–иҖ…еҸідҫ§еј№еҮәпјҲд»…еҲқе§ӢеҢ–з”ҹж•ҲпјүпјҢз»„д»¶еҶ…йғЁеҸҜд»Ҙж”ҫзҪ®д»»дҪ•еҶ…е®№гҖӮзӮ№еҮ»йЎөйқўжҢүй’®еҚіеҸҜжҳҫзӨәеҜјиҲӘиҸңеҚ•гҖӮ</text>
		</uni-card>

		<uni-section title="е·Ұдҫ§ж»‘еҮә" type="line">
			<view class="example-body">
				<button type="primary" @click="showDrawer('showLeft')"><text class="word-btn-white">жҳҫзӨәDrawer</text>
				</button>
				<uni-drawer ref="showLeft" mode="left" :width="320" @change="change($event,'showLeft')">
					<view class="close">
						<button @click="closeDrawer('showLeft')"><text class="word-btn-white">е…ій—ӯDrawer</text></button>
					</view>
				</uni-drawer>
			</view>
		</uni-section>

		<uni-section title="еҸідҫ§ж»‘еҮә" type="line">
			<view class="example-body">
				<button type="primary" @click="showDrawer('showRight')"><text class="word-btn-white">жҳҫзӨәDrawer</text>
				</button>
				<uni-drawer ref="showRight" mode="right" :mask-click="false" @change="change($event,'showRight')">
					<view class="scroll-view">
						<scroll-view class="scroll-view-box" scroll-y="true">
							<view class="info">
								<text class="info-text">еҸідҫ§йҒ®зҪ©еҸӘиғҪйҖҡиҝҮжҢүй’®е…ій—ӯпјҢдёҚиғҪйҖҡиҝҮзӮ№еҮ»йҒ®зҪ©е…ій—ӯ</text>
							</view>
							<view class="close">
								<button @click="closeDrawer('showRight')"><text
										class="word-btn-white">е…ій—ӯDrawer</text></button>
							</view>
							<view class="info-content" v-for="item in 100" :key="item">
								<text>еҸҜж»ҡеҠЁеҶ…е®№ {{item}}</text>
							</view>
							<view class="close">
								<button @click="closeDrawer('showRight')"><text
										class="word-btn-white">е…ій—ӯDrawer</text></button>
							</view>
						</scroll-view>
					</view>
				</uni-drawer>
			</view>
		</uni-section>
	</view>
</template>
<script>
	export default {
		data() {
			return {
				showRight: false,
				showLeft: false
			}
		},
		methods: {
			confirm() {},
			// жү“ејҖзӘ—еҸЈ
			showDrawer(e) {
				this.$refs[e].open()
			},
			// е…ій—ӯзӘ—еҸЈ
			closeDrawer(e) {
				this.$refs[e].close()
			},
			// жҠҪеұүзҠ¶жҖҒеҸ‘з”ҹеҸҳеҢ–и§ҰеҸ‘
			change(e, type) {
				console.log((type === 'showLeft' ? 'е·ҰзӘ—еҸЈ' : 'еҸізӘ—еҸЈ') + (e ? 'жү“ејҖ' : 'е…ій—ӯ'));
				this[type] = e
			}
		},
		onNavigationBarButtonTap(e) {
			if (this.showLeft) {
				this.$refs.showLeft.close()
			} else {
				this.$refs.showLeft.open()
			}
		},
		// appз«ҜжӢҰжҲӘиҝ”еӣһдәӢд»¶ пјҢд»…appз«Ҝз”ҹж•Ҳ
		onBackPress() {
			if (this.showRight || this.showLeft) {
				this.$refs.showLeft.close()
				this.$refs.showRight.close()
				return true
			}
		}
	}
</script>

<style lang="scss">
	.example-body {
		padding: 10px;
	}

	.scroll-view {
		/* #ifndef APP-NVUE */
		width: 100%;
		height: 100%;
		/* #endif */
		flex: 1
	}

	// еӨ„зҗҶжҠҪеұүеҶ…е®№ж»ҡеҠЁ
	.scroll-view-box {
		flex: 1;
		position: absolute;
		top: 0;
		right: 0;
		bottom: 0;
		left: 0;
	}

	.info {
		padding: 15px;
		color: #666;
	}

	.info-text {
		font-size: 14px;
		color: #666;
	}

	.info-content {
		padding: 5px 15px;
	}

	.close {
		padding: 10px;
	}
</style>
